"use strict";(self.webpackChunkmy_website=self.webpackChunkmy_website||[]).push([[2256],{7674:e=>{e.exports=JSON.parse('{"version":{"pluginId":"default","version":"current","label":"Next","banner":null,"badge":false,"noIndex":false,"className":"docs-version-current","isLast":true,"docsSidebars":{"tutorialSidebar":[{"type":"link","href":"/docs/intro","label":"About PACT","docId":"intro","unlisted":false},{"type":"category","label":"Operations","items":[{"type":"link","href":"/docs/operations/activation","label":"Activation","docId":"operations/activation","unlisted":false},{"type":"link","href":"/docs/operations/staffing-assignments-reporting","label":"Deployment","docId":"operations/staffing-assignments-reporting","unlisted":false},{"type":"link","href":"/docs/operations/frequency-allocation","label":"PACT Frequencies","docId":"operations/frequency-allocation","unlisted":false}],"collapsed":true,"collapsible":true},{"type":"category","label":"Training","items":[{"type":"link","href":"/docs/training/weekly-training-net","label":"Weekly Training Net","docId":"training/weekly-training-net","unlisted":false},{"type":"link","href":"/docs/training/meetings","label":"Interface Meetings","docId":"training/meetings","unlisted":false},{"type":"link","href":"/docs/training/certification","label":"Certification Levels","docId":"training/certification","unlisted":false},{"type":"link","href":"/docs/training/training-exercises","label":"Training Exercises & Events","docId":"training/training-exercises","unlisted":false}],"collapsed":true,"collapsible":true},{"type":"category","label":"Resources","items":[{"type":"link","href":"/docs/resources/radio-basics","label":"Radio Basics","docId":"resources/radio-basics","unlisted":false},{"type":"link","href":"/docs/resources/codes","label":"Codes","docId":"resources/codes","unlisted":false},{"type":"link","href":"/docs/resources/emergency-notification-systems","label":"Emergency Notification Systems","docId":"resources/emergency-notification-systems","unlisted":false},{"type":"link","href":"/docs/resources/forms","label":"Forms","docId":"resources/forms","unlisted":false},{"type":"link","href":"/docs/resources/local-groups","label":"Local Groups","docId":"resources/local-groups","unlisted":false},{"type":"link","href":"/docs/resources/lds-resources","label":"LDS Resources","docId":"resources/lds-resources","unlisted":false},{"type":"link","href":"/docs/resources/leadership-team","label":"Leadership Team","docId":"resources/leadership-team","unlisted":false}],"collapsed":true,"collapsible":true},{"type":"link","href":"/docs/get-involved","label":"Get Involved","docId":"get-involved","unlisted":false}]},"docs":{"get-involved":{"id":"get-involved","title":"Get Involved","description":"The Provo Auxiliary Communications Team (PACT) is made up of local volunteers who support emergency communications during disasters, city events, and other situations where reliable communication is needed. Joining is free and there is no annual membership fee. Membership applications are managed by the City of Provo.","sidebar":"tutorialSidebar"},"intro":{"id":"intro","title":"About PACT","description":"The Provo Auxiliary Communications Team (PACT) is a volunteer organization that works alongside local emergency management and public safety agencies during emergencies, major incidents, and community events.","sidebar":"tutorialSidebar"},"operations/activation":{"id":"operations/activation","title":"Activation","description":"Outside of planned exercises and events, PACT may be activated during emergencies or other incidents requiring auxiliary communications. PACT will only be activated under the direction of Provo\'s Emergency Manager.","sidebar":"tutorialSidebar"},"operations/frequency-allocation":{"id":"operations/frequency-allocation","title":"PACT Frequencies","description":"The following frequencies have been coordinated and allocated for PACT communications. PACT members should program these frequencies into their radio(s). District frequencies are to be used to share situational information, and assist with district-level communication efforts as directed.","sidebar":"tutorialSidebar"},"operations/staffing-assignments-reporting":{"id":"operations/staffing-assignments-reporting","title":"Deployment","description":"Step 4 of the Activation Process is Deploy & Report. During this phase, PACT members receive assignments, deploy to locations, establish communications, and relay information to Net Control.","sidebar":"tutorialSidebar"},"resources/codes":{"id":"resources/codes","title":"Codes","description":"Radio codes help reduce misunderstandings, improve efficiency, and ensure that important information is transmitted consistently between operators.","sidebar":"tutorialSidebar"},"resources/emergency-notification-systems":{"id":"resources/emergency-notification-systems","title":"Emergency Notification Systems","description":"Emergency notification systems provide timely information before, during, and after emergencies. PACT members should be familiar with the primary alerting systems used within Provo, Utah County, and Brigham Young University, as these systems are often the first source of information regarding severe weather, public safety incidents, evacuations, and other emergency situations. Monitoring official notifications can improve situational awareness, support informed decision-making, and help operators anticipate potential communication activations.","sidebar":"tutorialSidebar"},"resources/forms":{"id":"resources/forms","title":"Forms","description":"Forms are used to collect, organize, and relay emergency communications information in a clear, accurate, and consistent format. PACT members should keep printed copies of commonly used forms readily available during activations, training exercises, and public service events to support efficient message handling and record keeping.","sidebar":"tutorialSidebar"},"resources/lds-resources":{"id":"resources/lds-resources","title":"LDS Resources","description":"While the Provo Auxiliary Communications Team (PACT) is not associated with any faith based organization, members of the Church of Jesus Christ of Latter-day Saints constitute roughly 90% of Provo\'s population. This page is intended to help members of Provo\'s predominant faith based organization find resources for creating and updating Ward/Stake Emergency Response Plans.","sidebar":"tutorialSidebar"},"resources/leadership-team":{"id":"resources/leadership-team","title":"Leadership Team","description":"<img","sidebar":"tutorialSidebar"},"resources/local-groups":{"id":"resources/local-groups","title":"Local Groups","description":"Utah County Amature Radio Emergency Service (UCARES)","sidebar":"tutorialSidebar"},"resources/radio-basics":{"id":"resources/radio-basics","title":"Radio Basics","description":"Radio Waves","sidebar":"tutorialSidebar"},"training/certification":{"id":"training/certification","title":"Certification Levels","description":"The Provo Auxiliary Communications Team (PACT) certification program is designed to prepare members for emergency operations through structured training and real-world participation.","sidebar":"tutorialSidebar"},"training/meetings":{"id":"training/meetings","title":"Interface Meetings","description":"May 27, 2026","sidebar":"tutorialSidebar"},"training/training-exercises":{"id":"training/training-exercises","title":"Training Exercises & Events","description":"Provo Prepared Emergency Communications Exercise","sidebar":"tutorialSidebar"},"training/weekly-training-net":{"id":"training/weekly-training-net","title":"Weekly Training Net","description":"When30 PM (2030 local time)","sidebar":"tutorialSidebar"}}}}')}}]);